        def range_sum(l, r):
            return prefix[r] - prefix[l]

        def check(k):
            if k*(k+1)//2 > n:
                return False
            if k == 0:
                return True

            INF = float('inf')

            # Process from segment k (length 1) back to segment 1 (length k)
            # dp[j] = sum of segment starting at j (length current), INF if invalid
            # For last segment (length 1), all positions are valid
            length = 1
            dp = [INF]*n
            for j in range(n - length + 1):
                dp[j] = range_sum(j, j+length)

            # suffix max of dp
            suf_max = [-INF]*(n+1)
            for j in range(n-1, -1, -1):
                suf_max[j] = max(suf_max[j+1], dp[j])

            # Process segments from (k-1)-th down to 1st
            # seg_num: current segment number (1-indexed), length = k+1-seg_num
            for seg_num in range(k-1, 0, -1):
                length = k + 1 - seg_num
                new_dp = [INF]*n
                for j in range(n - length + 1):
                    s = range_sum(j, j+length)
                    nxt_start = j + length
                    # Need existence of valid next segment starting >= nxt_start with sum > s
                    if nxt_start <= n and suf_max[nxt_start] > s:
                        new_dp[j] = s

                dp = new_dp
                suf_max = [-INF]*(n+1)
                for j in range(n-1, -1, -1):
                    suf_max[j] = max(suf_max[j+1], dp[j])

            return any(v < INF for v in dp)

        hi = 0
        while (hi+1)*(hi+2)//2 <= n:
            hi += 1

        ans = 0
        lo, hi = 0, hi
        while lo <= hi:
            mid = (lo+hi)//2
            if check(mid):
                ans = mid
                lo = mid+1
            else:
                hi = mid-1

        print(ans)

